toolCalls.args:
{"command": "DBGFILE="/tmp/symbols/libmonosgen-2.0.so.debug"

# Check which section numbers correspond to which sections
echo "=== Section headers ==="
readelf -S "$DBGFILE" 2>/dev/null | head -30

echo ""
echo "=== Any FUNC symbol that contains 0x2f4b20 or 0x2f4c84 ==="
readelf -Ws "$DBGFILE" 2>/dev/null | awk '
$4 == "FUNC" {
    addr = strtonum("0x"$2)
    size = strtonum("0x"$3)
    if (size > 0) {
        if (addr <= 0x2f4b20 && (addr+size) > 0x2f4b20) print "0x2f4b20:", $0
        if (addr <= 0x2f4c84 && (addr+size) > 0x2f4c84) print "0x2f4c84:", $0
    }
}'

echo ""
echo "=== Largest FUNC symbols in the sgen/gc region ==="
readelf -Ws "$DBGFILE" 2>/dev/null | awk '
$4 == "FUNC" {
    addr = strtonum("0x"$2)
    size = strtonum("0x"$3)
    if (addr >= 0x290000 && addr <= 0x310000 && size > 500) print addr, "0x"$2, size, $NF
}' | sort -n", "description": "Check section mappings and broader symbol search"}
